    const moduleSymbol = resolveExternalModuleNameWorker(specifier!, specifier!, /*moduleNotFoundError*/ undefined); // TODO: GH#18217
    if (!moduleSymbol) {
        return undefined;
    }
    return getDeclarationOfKind(moduleSymbol, SyntaxKind.SourceFile);
}

